const mockFindByEmail = jest.fn();
const mockInsert = jest.fn();
const mockSendWelcome = jest.fn();

jest.spyOn(userRepo, 'findByEmail').mockImplementation(mockFindByEmail);
jest.spyOn(userRepo, 'insert').mockImplementation(mockInsert);
jest.spyOn(emailService, 'sendWelcome').mockImplementation(mockSendWelcome);

describe('createUser', () => {
  test('inserts user and sends welcome email', async () => {
    mockFindByEmail.mockResolvedValue(null);
    mockInsert.mockResolvedValue({ id: 1 });
    mockSendWelcome.mockResolvedValue(undefined);
    await createUser({ email: 'test@example.com' });
    expect(mockInsert).toHaveBeenCalled();
    expect(mockSendWelcome).toHaveBeenCalled();
  });

  test('throws when user already exists as duplicate', async () => {
    mockFindByEmail.mockResolvedValue({ id: 1, email: 'test@example.com' });
    await expect(createUser({ email: 'test@example.com' })).rejects.toThrow('existing user');
  });
});
```

jest.fn() and jest.spyOn stubs replace the database and email dependencies to keep tests fast and isolated.

