describe('Counter', () => {
  test('increment increases value', () => {
    const c = new Counter(0);
    c.increment();
    expect(c.getValue()).toBe(1);
  });

  test('decrement decreases value', () => {
    const c = new Counter(5);
    c.decrement();
    expect(c.getValue()).toBe(4);
  });

  test('reset returns to initialValue', () => {
    const c = new Counter(3);
    c.increment();
    c.reset();
    expect(c.getValue()).toBe(3);
  });

  test('throws RangeError on decrement below zero (negative guard)', () => {
    const c = new Counter(0);
    expect(() => c.decrement()).toThrow(RangeError);
  });

  test('sequence: multiple calls chain correctly â€” after increment then decrement', () => {
    const c = new Counter(0);
    c.increment();
    c.increment();
    c.decrement();
    expect(c.getValue()).toBe(1);
  });
});
```

